SELECT
/* @SQLID=FCT003#Sql002 */
TRIM(PRODUCT_CD) AS PRODUCT_CD
, TRIM(TRADE_CD) AS TRADE_CD
, COUNTRY_CD
, CURRENCY_CODE
, VALUE
FROM
M_MED_PROPRIETY
WHERE
CUSTOMER_ATTRIBUTE = #{fct003Sql002RequestModel.customerAttribute}

    AND TRIM(PRODUCT_CD) = #{fct003Sql002RequestModel.productCd}


    AND TRIM(TRADE_CD) = #{fct003Sql002RequestModel.tradeCd}


    AND COUNTRY_CD = #{fct003Sql002RequestModel.countryCd}


    AND CURRENCY_CODE = #{fct003Sql002RequestModel.currencyCode}

AND START_DATE <= IFA_DATE_UTIL.IFA_GET_DATE
AND END_DATE >= IFA_DATE_UTIL.IFA_GET_DATE
